import { useParams } from "react-router-dom";
import styled from "styled-components";

const allProducts = [
  {
    id: 1,
    name: "iPhone 15",
    category: "celular",
    price: 5999,
    oldPrice: 6999,
    description: "O mais novo iPhone com performance absurda.",
    image: "https://via.placeholder.com/500"
  },
  {
    id: 2,
    name: "Notebook Gamer",
    category: "notebook",
    price: 7499,
    oldPrice: 8199,
    description: "Alta performance para jogos e produtividade.",
    image: "https://via.placeholder.com/500"
  }
];

const ProductDetail = () => {
  const { id } = useParams();

  const product = allProducts.find(
    p => p.id === Number(id)
  );

  if (!product) {
    return <NotFound>Produto nĂŁo encontrado</NotFound>;
  }

  return (
    <Container>
      <ImageSection>
        <ProductImage src={product.image} />
      </ImageSection>

      <InfoSection>
        <Category>{product.category}</Category>
        <Title>{product.name}</Title>

        <PriceContainer>
          <OldPrice>R$ {product.oldPrice}</OldPrice>
          <NewPrice>R$ {product.price}</NewPrice>
        </PriceContainer>

        <Description>
          {product.description}
        </Description>

        <BuyButton>
          Comprar agora
        </BuyButton>
      </InfoSection>
    </Container>
  );
};

export default ProductDetail;

const Container = styled.div`
  display: flex;
  gap: 80px;
  padding: 140px 100px;
  background: #0D0D0D;
  min-height: 100vh;
`;
const ImageSection = styled.div`
  flex: 1;
  display: flex;
  justify-content: center;
  align-items: center;
`;
const ProductImage = styled.img`
  width: 500px;
  object-fit: contain;
`;
const InfoSection = styled.div`
  flex: 1;
  color: white;
`;
const Category = styled.span`
  color: #7C3AED;
  text-transform: uppercase;
  font-size: 14px;
`;
const Title = styled.h1`
  font-size: 42px;
  margin: 20px 0;
  font-family: 'Space Grotesk';
`;
const PriceContainer = styled.div`
  display: flex;
  gap: 15px;
  align-items: center;
  margin-bottom: 20px;
`;
const OldPrice = styled.span`
  text-decoration: line-through;
  color: #888;
  font-size: 18px;
`;
const NewPrice = styled.span`
  color: #7C3AED;
  font-size: 28px;
  font-weight: bold;
`;
const Description = styled.p`
  color: #A1A1AA;
  line-height: 1.6;
  margin-bottom: 30px;
`;
const BuyButton = styled.button`
  padding: 15px 40px;
  background: linear-gradient(90deg, #7C3AED, #9333EA);
  border: none;
  border-radius: 10px;
  color: white;
  font-weight: bold;
  cursor: pointer;
  transition: 0.3s;

  &:hover {
    transform: translateY(-3px);
    box-shadow: 0 10px 25px rgba(124, 58, 237, 0.5);
  }
`;
const NotFound = styled.div`
  padding: 200px;
  text-align: center;
  color: white;
  background: #0D0D0D;
`;
